const t=JSON.parse(`{"key":"v-7bbd925a","path":"/zh/posts/%E6%9D%82%E8%B0%88/%E7%BC%96%E7%A8%8B%E6%9D%82%E8%B0%88/%E9%9C%87%E6%83%8A_1_0.html","title":"震惊,1=0","lang":"zh-CN","frontmatter":{"name":"震惊,1=0","icon":"edit","date":"2022-01-01T00:00:00.000Z","category":["杂谈"],"tag":["杂谈/编程杂谈"],"description":"震惊,1=0 事情的起因 起因是我正在DragonOS写 Signal 相关的代码，然后 Page fault 了，经过一系列排查之后，发现 RIP 寄存器的值好像不太对，把内核反编译之后发现确实不对，它没指向任何一个函数入口。到这一步，很自然的想法是栈损坏了，或者某些原因导致了 Dirty bit。这里先提一嘴，就是 DragonOS 里中断栈帧的RIP是 u64，而 Signal 中的函数指针是 c_void。后者在 rust 中打日志的时候会被格式化成十六进制。 扑朔迷离","head":[["meta",{"property":"og:url","content":"https://chiichen.github.io/zh/posts/%E6%9D%82%E8%B0%88/%E7%BC%96%E7%A8%8B%E6%9D%82%E8%B0%88/%E9%9C%87%E6%83%8A_1_0.html"}],["meta",{"property":"og:site_name","content":"ChiChen's Blog"}],["meta",{"property":"og:title","content":"震惊,1=0"}],["meta",{"property":"og:description","content":"震惊,1=0 事情的起因 起因是我正在DragonOS写 Signal 相关的代码，然后 Page fault 了，经过一系列排查之后，发现 RIP 寄存器的值好像不太对，把内核反编译之后发现确实不对，它没指向任何一个函数入口。到这一步，很自然的想法是栈损坏了，或者某些原因导致了 Dirty bit。这里先提一嘴，就是 DragonOS 里中断栈帧的RIP是 u64，而 Signal 中的函数指针是 c_void。后者在 rust 中打日志的时候会被格式化成十六进制。 扑朔迷离"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://chiichen.github.io/"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-10-16T03:16:33.000Z"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:image:alt","content":"震惊,1=0"}],["meta",{"property":"article:author","content":"Chi"}],["meta",{"property":"article:tag","content":"杂谈/编程杂谈"}],["meta",{"property":"article:published_time","content":"2022-01-01T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-10-16T03:16:33.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"震惊,1=0\\",\\"image\\":[\\"https://chiichen.github.io/\\"],\\"datePublished\\":\\"2022-01-01T00:00:00.000Z\\",\\"dateModified\\":\\"2023-10-16T03:16:33.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Chi\\"}]}"]]},"headers":[{"level":2,"title":"事情的起因","slug":"事情的起因","link":"#事情的起因","children":[]},{"level":2,"title":"扑朔迷离","slug":"扑朔迷离","link":"#扑朔迷离","children":[]},{"level":2,"title":"真相大白","slug":"真相大白","link":"#真相大白","children":[]}],"git":{"createdTime":1697426193000,"updatedTime":1697426193000,"contributors":[{"name":"ChiChen","email":"2531693734@qq.com","commits":1}]},"readingTime":{"minutes":2.06,"words":619},"filePathRelative":"zh/posts/杂谈/编程杂谈/震惊,1=0.md","localizedDate":"2022年1月1日","excerpt":"<h1> 震惊,1=0</h1>\\n<h2> 事情的起因</h2>\\n<p>起因是我正在DragonOS写 Signal 相关的代码，然后 Page fault 了，经过一系列排查之后，发现 RIP 寄存器的值好像不太对，把内核反编译之后发现确实不对，它没指向任何一个函数入口。到这一步，很自然的想法是栈损坏了，或者某些原因导致了 Dirty bit。这里先提一嘴，就是 DragonOS 里中断栈帧的RIP是 <code>u64</code>，而 Signal 中的函数指针是 <code>c_void</code>。后者在 rust 中打日志的时候会被格式化成十六进制。</p>\\n<h2> 扑朔迷离</h2>","autoDesc":true}`);export{t as data};
